//Firebase...
import {auth, provider} from "../config/firebase"
import {signInWithPopup} from "firebase/auth"

//React...
import { useState } from "react";

//React-router...
import { useNavigate } from "react-router-dom"

//React-icons...
import {FcGoogle} from "react-icons/fc"
import MobileNav from "./Mobile-nav";

//Styles...
import "../styles/Login.scss"

const RECAPTCHA_SITE_KEY = "6LeVhb8sAAAAALH4KD8aRV1Q3FXV2m8IsMdyjwFr";
const RECAPTCHA_LOGIN_ACTION = "LOGIN";

export default function Login() {
    const navigate = useNavigate()
    const [isSigningIn, setIsSigningIn] = useState(false);
    const [errorMessage, setErrorMessage] = useState("");

    const runRecaptcha = async () => {
        const captcha = window.grecaptcha?.enterprise;

        if (!captcha) {
            throw new Error("reCAPTCHA did not load. Please refresh and try again.");
        }

        await new Promise((resolve) => {
            captcha.ready(resolve);
        });

        const token = await captcha.execute(RECAPTCHA_SITE_KEY, {
            action: RECAPTCHA_LOGIN_ACTION,
        });

        if (!token) {
            throw new Error("reCAPTCHA verification failed. Please try again.");
        }

        return token;
    };

    const signUpWithGoogle = async (e) => {
        e.preventDefault();
        setErrorMessage("");
        setIsSigningIn(true);

        try {
            await runRecaptcha();
            await signInWithPopup(auth, provider);
            navigate("/");
        } catch (error) {
            setErrorMessage(error?.message || "Login failed. Please try again.");
        } finally {
            setIsSigningIn(false);
        }
    }

    return (
        <section className="login-page">
            <MobileNav />
            <article>
                <h1>Welcome Back</h1>
                <p>Sign in to save bookmarks and join the community feed.</p>
                <button onClick={signUpWithGoogle} disabled={isSigningIn}>
                    <FcGoogle/>
                    {isSigningIn ? "Verifying..." : "Sign in with Google"}
                </button>
                {errorMessage && <p className="login-error">{errorMessage}</p>}
            </article>
        </section>
    )
}
